                  </View>
                  <Text style={styles.ownerEquipment}>{owner.equipmentCount} {t('equipment_count')}</Text>
                </View>
              </Pressable>
            </>
          )}

          {!isAuthenticated && (
            <View style={styles.authBanner}>
              <Lock size={18} color={Colors.gold} />
